package com.aadil.jobtracker.exceptions;import lombok.Getter;import java.time.LocalDateTime;@Getterpublic class ErrorResponse {    private final String message;    private final int status;    private final LocalDateTime timeStamp;    public ErrorResponse(String message,int status,LocalDateTime timeStamp){        this.message=message;        this.status=status;        this.timeStamp=timeStamp;    }}